-- ============================================================
-- 004 — Adiciona campos e importa produtos do controle de estoque
-- Rodar no Supabase: SQL Editor → colar tudo → Run
-- Seguro para rodar mais de uma vez (ON CONFLICT ... DO UPDATE)
-- ============================================================

-- PASSO 1: Adicionar novas colunas à tabela products
ALTER TABLE products
  ADD COLUMN IF NOT EXISTS category     text,
  ADD COLUMN IF NOT EXISTS supplier     text,
  ADD COLUMN IF NOT EXISTS supplier_link text;

-- PASSO 2: Importar os 117 produtos do CSV
-- Mapeamento de categorias:
--   C=Cesta | FT=Fita | FL=Flor | VE=Vela | CHO=Chocolate
--   PERF=Perfume | HIDR=Hidratante | ALC=Sanitizante
--   SBM=Sabonete Líquido | GSBM=Sabonete Gel
--   EN=Envelope | CAR=Papel de Carta | SL=Selo/Tag | SD=Papel de Embrulho
--   MAN=Manta | COL=Colher | CAN=Caneca | ES=Espelho
--   BC=Body Cream | BW=Body Wash | BL=Body Lotion
--   SBB=Sabonete em Barra | TBW=Travel Body Wash | TBC=Travel Body Cream
--   TPSL/TPSS=Protetor Solar | TMIST=Travel Mist | PAPEL=Papel

ON CONFLICT (sku) DO UPDATE SET
  name              = EXCLUDED.name,
  stock_quantity    = EXCLUDED.stock_quantity,
  cost_price        = EXCLUDED.cost_price,
  sale_price        = EXCLUDED.sale_price,
  low_stock_threshold = EXCLUDED.low_stock_threshold,
  category          = EXCLUDED.category,
  supplier          = EXCLUDED.supplier,
  supplier_link     = EXCLUDED.supplier_link;

-- Verificação rápida
SELECT COUNT(*) AS total_importado FROM products;
